import React from 'react';
import bullesDevImage from './requindev.png';
import './header.css';
import { Link } from 'react-scroll'; // Importez le composant Link de react-scroll

const Header = () => {
  const scrollToProjects = () => {
    // Votre logique de défilement ici
  };

  return (
    <header>
      <div className="bullesdev">
        <img src={bullesDevImage} alt="Les bulles du dev" />
      </div>
      <nav>
        <div className="liensnav">
          <Link to="accueil" spy={true} smooth={true}>
            <p>Accueil</p>
          </Link>
          <Link to="pageQjs" spy={true} smooth={true}>
            <p>Mon évolution</p>
          </Link>
          <Link to="competences" spy={true} smooth={true}>
            <p>Mes compétences</p>
          </Link>
          <Link to="projets" spy={true} smooth={true}>
            <p>Mes projets réalisés</p>
          </Link>
          <Link to="footer" spy={true} smooth={true}>
            <p>Contact</p>
          </Link>
        </div>
      </nav>
    </header>
  );
};

export default Header;
